if (dieTotal !== 20) return;

const t = token?.object ?? token;
if (!t) return;

canvas.interface.createScrollingText(t.center, "Critical Hit!", {
  anchor: CONST.TEXT_ANCHOR_POINTS.TOP,
  direction: CONST.TEXT_ANCHOR_POINTS.TOP,
  duration: 3000,
  fontFamily: "Modesto Condensed",
  fontSize: 36,
  fill: "#ff2020",
  stroke: "#000000",
  strokeThickness: 4
});
